cp-4-move-cleaning-to-module.starterCode:
def clean_row(line):
    name, score, email = line.strip().split(",")
    return {"name": name.strip().title(), "score": int(score), "email": email.strip().lower()}

# Move clean_row(line) into tools/cleaning.py.
# Then import it back here so main.py keeps only the roster workflow.

records = []
with open("data/roster.csv") as file:
    next(file)
    for line in file:
        try:
            records.append(clean_row(line))
        except ValueError:
            continue

print(records)
